// Определяем тип входящего апдейта от Max Trigger
const update = $input.item.json;

const updateType = update.update_type || '';

const isCallback = updateType === 'message_callback';
const isMessage  = updateType === 'message_created';
const isBotStart = updateType === 'bot_started';

let chatId, userId, text, callbackData, username, firstName;

if (isCallback) {
  // update.callback — объект callback
  const cb = update.callback;
  userId   = cb.user?.user_id || '';
  username = cb.user?.username || '';
  firstName = cb.user?.name || '';
  chatId   = cb.message?.recipient?.chat_id || '';
  callbackData = cb.payload || '';
  text = '';

} else if (isMessage) {
  // update.message — объект сообщения
  const msg = update.message;
  userId    = msg.sender?.user_id || '';
  username  = msg.sender?.username || '';
  firstName = msg.sender?.name || '';
  chatId    = msg.recipient?.chat_id || '';
  text      = msg.body?.text || '';
  callbackData = '';

} else if (isBotStart) {
  // update.user — пользователь, update.chat_id — чат
  userId    = update.user?.user_id || '';
  username  = update.user?.username || '';
  firstName = update.user?.name || '';
  chatId    = update.chat_id || '';
  text      = '';
  callbackData = '';

} else {
  // Неизвестный тип — возвращаем пустые значения
  chatId = userId = username = firstName = text = callbackData = '';
}

const isStart = text === '/start' || isBotStart;

return [{
  json: {
    chatId,
    userId,
    username,
    firstName,
    text,
    callbackData,
    isCallback,
    isMessage,
    isStart,
    updateType,
    isVoice: !!(update.message?.body?.attachments?.some(a => a.type === 'audio'))
  }
}];
